/**
 * WeaverMarshal serializes a Transaction object into binary format using the provided encoder.
 * This method implements custom marshaling for Transaction objects to be used with the Weaver 
 * serialization framework. It encodes account numbers, routing numbers, transaction amount, 
 * and timestamp in a specific order.
 *
 * @param enc The encoder to use for serializing the transaction data
 * @panics If the receiver (x) is nil
 */
func (x *Transaction) WeaverMarshal(enc *codegen.Encoder) {
	// Check for nil receiver to avoid runtime errors during encoding
	if x == nil {
		panic(fmt.Errorf("Transaction.WeaverMarshal: nil receiver"))
	}

	// Encode the transaction details in a specific sequence:
	// source account information, destination account information,
	// transaction amount, and timestamp
	enc.String(x.FromAccountNum)
	enc.String(x.FromRoutingNum)
	enc.String(x.ToAccountNum)
	enc.String(x.ToRoutingNum)
	enc.Int64(x.Amount)
	enc.EncodeBinaryMarshaler(&x.Timestamp)
}
