/**
 * Removes a menu item from the list of visible items for a specific parent menu.
 * This function safely handles the concurrent access to the visible items map
 * and removes the specified item value from the parent's visible items slice.
 *
 * @param parent The parent menu identifier
 * @param val The menu item identifier to be removed
 */
func (t *winTray) delFromVisibleItems(parent, val uint32) {
	// Lock the mutex to ensure thread-safe access to the visibleItems map
	t.muVisibleItems.Lock()
	defer t.muVisibleItems.Unlock()

	// Get the slice of visible items for the specified parent menu
	visibleItems := t.visibleItems[parent]

	// Find and remove the specified item from the visible items slice
	for i, itemval := range visibleItems {
		if val == itemval {
			t.visibleItems[parent] = append(visibleItems[:i], visibleItems[i+1:]...)
			break
		}
	}
}
