 * @return The decrypted plaintext and any error encountered during decryption
 */
func decrypt(key tink.AEAD, ciphertext []byte, dataId string) ([]byte, error) {
	// Validate that dataId is not empty as it's required for associated data
	if len(dataId) == 0 {
		return nil, fmt.Errorf("data id cannot be empty")
	}

