/**
 * Handles bearer authentication for API requests by checking if the requested operation
 * is restricted for bearer token authentication. If the operation is restricted,
 * it returns an unauthorized error, otherwise it allows the request to proceed.
 *
 * @param c The Echo context containing the HTTP request and response
 * @param r Route information including the operation ID being requested
 * @return An error if the operation is restricted, nil otherwise
 */
func (a *AuthZ) handleBearerAuth(c echo.Context, r *middleware.RouteInfo) error {
    // Check if the requested operation is in the list of operations restricted for bearer token authentication
    // If it is restricted, return an unauthorized error to prevent access
    if operationIn(r.OperationID, restrictedWithBearerToken) {
        return echo.NewHTTPError(http.StatusUnauthorized, "Not authorized to perform this operation")
    }

    // Operation is allowed with bearer token, proceed with the request
    return nil
}
