/**
 * Creates and returns a function that updates the ticker's heartbeat timestamp.
 * This function is typically used to periodically signal that the ticker is still active.
 * The returned function logs the heartbeat update, records the current time as the 
 * last heartbeat timestamp in the repository, and logs any errors that occur.
 *
 * @param ctx The context for database operations
 * @return A function that performs the heartbeat update when called
 */
func (t *TickerImpl) runUpdateHeartbeat(ctx context.Context) func() {
	return func() {
		// Log that a heartbeat update is being performed
		t.l.Debug().Msgf("ticker: updating heartbeat")

		// Get current UTC time to use as the heartbeat timestamp
		now := time.Now().UTC()

		// Update the ticker's heartbeat timestamp in the repository
		_, err := t.repo.Ticker().UpdateTicker(ctx, t.tickerId, &repository.UpdateTickerOpts{
			LastHeartbeatAt: &now,
		})

		// Log any errors that occurred during the update
		if err != nil {
			t.l.Err(err).Msg("could not update heartbeat")
		}
	}
}
