 * Determines if a given type is a Protocol Buffers message type.
 * This function checks if the provided type is a named type that corresponds 
 * to the protoreflect.Message interface from the Protocol Buffers library.
 *
 * @param t - The type to check
 * @return bool - True if the type is a Protocol Buffers message, false otherwise
 */
func isProtoMessage(t types.Type) bool {
	// Check if the type is a named type, return false otherwise
	n, ok := t.(*types.Named)
	if !ok {
		return false
	}

	// Check if the type is specifically the protoreflect.Message interface
	// by verifying both the package path and type name
	const protoreflect = "google.golang.org/protobuf/reflect/protoreflect"
	return n.Obj().Pkg().Path() == protoreflect && n.Obj().Name() == "Message"
}
