/**
 * Closes all active stream entries in a TCP stream, processes any property updates that result from
 * closing these streams, logs updates if properties changed, and moves all entries from the active
 * list to the done list.
 */
func (s *tcpStream) closeActiveEntries() {
	// Process all active entries: close each stream, collect and track property updates
	updated := false
	for _, entry := range s.activeEntries {
		update := entry.Stream.Close(false)
		up := processPropUpdate(s.info.Props, entry.Name, update)
		updated = updated || up
	}

	// Log property updates if any occurred during the closing process
	if updated {
		s.logger.TCPStreamPropUpdate(s.info, true)
	}

	// Move all entries from active to done list and clear the active entries
	s.doneEntries = append(s.doneEntries, s.activeEntries...)
	s.activeEntries = nil
}
