/**
 * Extracts the Bearer token from an HTTP request's Authorization header.
 * Returns the token as a string or an error if the Authorization header
 * is missing or improperly formatted.
 */
func getBearerTokenFromRequest(r *http.Request) (string, error) {
	// Extract the Authorization header from the request
	reqToken := r.Header.Get("Authorization")
	splitToken := strings.Split(reqToken, "Bearer")

	// Validate that the header contains a properly formatted Bearer token
	if len(splitToken) != 2 {
		return "", errInvalidAuthHeader
	}

	// Clean up the token by removing any leading/trailing whitespace
	reqToken = strings.TrimSpace(splitToken[1])

	return reqToken, nil
}
