/**
 * Returns the appropriate file path for the Ollama configuration file based on the user's permissions.
 * For root users, the configuration is stored in the system directory, otherwise in the user's home directory.
 */
func getStorePath() string {
	// For root users (euid=0), use the system-wide configuration path
	if os.Geteuid() == 0 {
		return "/etc/ollama/config.json"
	}

	// For regular users, use the configuration file in the user's home directory
	home := os.Getenv("HOME")
	return filepath.Join(home, ".ollama", "config.json")
}
