/**
 * GetUntil retrieves bytes from the buffer up to a specified separator.
 * 
 * This function searches for the first occurrence of a separator sequence in the buffer
 * and returns the bytes up to (and optionally including) that separator.
 *
 * @param sep The separator byte sequence to search for
 * @param includeSep Whether to include the separator in the returned data
 * @param consume Whether to remove the returned data from the buffer
 * @return The extracted byte slice and a boolean indicating success
 */
func (b *ByteBuffer) GetUntil(sep []byte, includeSep, consume bool) (data []byte, ok bool) {
	// Find the position of the separator in the buffer
	// If not found, return false to indicate failure
	index := b.Index(sep)
	if index == -1 {
		return nil, false
	}

	// If includeSep is true, adjust the index to include the separator in the result
	if includeSep {
		index += len(sep)
	}

	// Extract the data up to the calculated index, consuming it if requested
	return b.Get(index, consume)
}
