/**
 * Do executes the callback function with the provided value in a separate goroutine.
 * It recovers from any panics that might occur during callback execution and converts them into errors.
 * The function returns immediately after launching the goroutine without waiting for completion.
 *
 * @param v The value to pass to the callback function
 * @return An error if a panic occurred during callback setup, nil otherwise
 */
func (c Callback[T]) Do(v T) (err error) {
	// Set up panic recovery to prevent the application from crashing
	// if the callback function panics. Converts panics to errors.
	defer func() {
		if r := recover(); r != nil {
			err = fmt.Errorf("panic in callback: %v", r)
		}
	}()

	// Execute the callback in a separate goroutine to allow non-blocking operation.
	// The errcheck linter is disabled as we intentionally don't check the return value.
	go c(v) // nolint: errcheck

	return err
}
