/**
 * Creates a new TCP stream analyzer for DNS protocol. This function initializes a DNS TCP stream
 * with buffers for request and response data, and sets up state machines to handle message parsing.
 *
 * @param info Information about the TCP connection
 * @param logger Logger interface for recording analysis results
 * @return A configured TCPStream analyzer for DNS traffic
 */
func (a *DNSAnalyzer) NewTCP(info analyzer.TCPInfo, logger analyzer.Logger) analyzer.TCPStream {
	// Initialize a new DNS TCP stream with logger and buffers for request and response data
	s := &dnsTCPStream{logger: logger, reqBuf: &utils.ByteBuffer{}, respBuf: &utils.ByteBuffer{}}

	// Set up the request state machine to first get message length, then process the message
	s.reqLSM = utils.NewLinearStateMachine(
		s.getReqMessageLength,
		s.getReqMessage,
	)

	// Set up the response state machine with similar flow: length determination followed by message processing
	s.respLSM = utils.NewLinearStateMachine(
		s.getRespMessageLength,
		s.getRespMessage,
	)

	return s
}
