/**
 * Generates a unique identity string for the current process by combining hostname, 
 * any hostname error, and process ID, then hashing the combined data using SHA-256.
 * 
 * @return A hex string representation of the SHA-256 hash that uniquely identifies this process.
 */
func identity() string {
	// Get the hostname and capture any error that might occur
	hostname, err := os.Hostname()

	// Create a SHA-256 hash from the hostname, any error encountered, and the current process ID
	// to generate a unique identifier for this process instance
	h := sha256.New()
	_, _ = fmt.Fprint(h, hostname)
	_, _ = fmt.Fprint(h, err)
	_, _ = fmt.Fprint(h, os.Getpid())

	// Return the hash as a hexadecimal string
	return fmt.Sprintf("%x", h.Sum(nil))
}
