/**
 * Decodes a binary header into its component parts: context metadata, method key, 
 * timestamp in microseconds, and trace span context. This function is used in RPC
 * communication to extract necessary information from the request header.
 *
 * @param hdr The binary header data to decode
 * @return A tuple containing the context with metadata, method key, timestamp in microseconds, and trace span context
 */
func decodeHeader(hdr []byte) (context.Context, MethodKey, int64, *trace.SpanContext) {
	// Create a decoder for the binary header data
	dec := codegen.NewDecoder(hdr)

	// Extract the method key which identifies the RPC method being called
	var hkey MethodKey
	copy(hkey[:], dec.Read(len(hkey)))

	// Extract the timestamp in microseconds
	micros := dec.Int64()

	// Extract the distributed tracing context information
	sc := readTraceContext(dec)

	// Extract any additional context metadata and create a new context with it
	ctx := readContextMetadata(context.Background(), dec)
	return ctx, hkey, micros, sc
}
