/**
 * Processes a UDP packet by matching it against existing UDP streams using a stream manager.
 * This function handles UDP traffic by identifying the stream it belongs to and determining
 * the appropriate action (verdict) to take for the packet.
 *
 * @param streamID The unique identifier for the UDP stream
 * @param ipFlow The IP flow information containing source and destination addresses
 * @param udp The UDP packet layer containing port information and payload
 * @return A verdict indicating how to handle the packet (accept, drop, etc.) and potentially modified packet data
 */
func (w *worker) handleUDP(streamID uint32, ipFlow gopacket.Flow, udp *layers.UDP) (io.Verdict, []byte) {
	// Create a context with default verdict of accept
	ctx := &udpContext{
		Verdict: udpVerdictAccept,
	}

	// Match the packet against existing UDP streams and let the stream manager process it
	// The stream manager may modify the context (verdict and packet) based on matching rules
	w.udpStreamManager.MatchWithContext(streamID, ipFlow, udp, ctx)

	return io.Verdict(ctx.Verdict), ctx.Packet
}
