/**
 * Validates if the given expression is a supported literal type.
 * Only constant expressions and timestamp function calls with valid arguments are allowed.
 * Returns nil if the expression is valid, otherwise returns an error.
 */
func restrictLiteral(e *exprpb.Expr) error {
	switch e.ExprKind.(type) {
	// Constant expressions are always allowed literals
	case *exprpb.Expr_ConstExpr:
		return nil

	// For function calls, only the "timestamp" function is supported
	case *exprpb.Expr_CallExpr:
		call := e.GetCallExpr()
		if f := call.Function; f != "timestamp" {
			return fmt.Errorf("unsupported literal: %v", e)
		}
		// Recursively check if the timestamp function's argument is a valid literal
		return restrictLiteral(call.Args[0])

	// All other expression types are not supported as literals
	default:
		return fmt.Errorf("unsupported literal: %v", e)
	}
}
